def with_history(func=None, history=None):
    """Decorator that records call history for a function.

    Can be used as either:
      @with_history
      def f(...): ...

    or
      @with_history(history=my_list)
      def f(...): ...

    Invariant: each decorated function must have its OWN
    independent history list unless an explicit list is provided.
    """
    # Support both @with_history and @with_history(history=...)
    if func is None:
        return lambda f: with_history(f, history=history)

    # If no history was provided, create a fresh list for this function
    if history is None:
        history = []

    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        history.append({"func": func.__name__, "args_count": len(args)})
        return result

    wrapper.get_history = lambda: list(history)
    wrapper.clear_history = lambda: history.clear()
    return wrapper


