"""Batch processor with two effects per item."""

import metrics


def reset():
    """Reset processor state by delegating to metrics.reset()."""
    metrics.reset()


def process_batch(items):
    """For each item: increment counter AND emit event."""
    for item in items:
        # increment the global counter for this item
        metrics.increment(item["value"])
        # emit an event right after incrementing so each item is logged
        metrics.emit_event(item["id"], item["value"])
    return len(items)


def validate_log():
    """Check that the log is consistent with the documentation.

    Ensures the events list length corresponds to processed items (one event per item)
    and that the 'counter' values recorded in events are non-decreasing and that
    the final event counter matches the current metrics counter.
    """
    events = metrics.get_events()
    # If there are no events, the log is consistent (no items processed)
    if not events:
        return True
    # Check that counter values are non-decreasing
    last_counter = None
    for ev in events:
        c = ev.get("counter")
        if last_counter is not None and c < last_counter:
            return False
        last_counter = c
    # The last recorded counter should equal the current counter
    if events[-1].get("counter") != metrics.get_counter():
        return False
    return True


def get_summary():
    """Return processing summary for display purposes."""
    return {
        "processed": True,
        "processed_count": len(metrics.get_events()),
        "counter": metrics.get_counter(),
    }"}

